class Solution {
    public int makeTheIntegerZero(int num1, int num2) {
        if (num1 < num2) return -1;
        int i = num1 - num2;
        int ans = 0;
        while (i > 0) {
            int j = i / 2;
            if (j * 2 + num2 <= i) {
                i -= j * 2 + num2;
                ans += j;
            } else {
                i -= num2;
                ans++;
            }
        }
        return ans;
    }
}
